/* jsPDF UMD - Professional PDF Generation */
/* Uses CDN with proper promise-based loading */

if (!window.jspdfPromise) {
  window.jspdfPromise = new Promise((resolve, reject) => {
    if (window.jspdf && window.jspdf.jsPDF) {
      console.log('[jsPDF] Already loaded');
      resolve(window.jspdf);
      return;
    }

    console.log('[jsPDF] Loading from CDN...');
    var script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';
    script.async = true;
    
    var timeout = setTimeout(() => {
      reject(new Error('jsPDF CDN load timeout'));
    }, 10000);
    
    script.onload = function() {
      clearTimeout(timeout);
      if (window.jspdf && window.jspdf.jsPDF) {
        console.log('[jsPDF] Successfully loaded from CDN');
        resolve(window.jspdf);
      } else {
        reject(new Error('jsPDF loaded but not available'));
      }
    };
    
    script.onerror = function() {
      clearTimeout(timeout);
      console.error('[jsPDF] CDN load failed, using fallback');
      window.jspdf = { jsPDF: class { constructor() { this.error = true; } save() { throw new Error('jsPDF not loaded'); } } };
      reject(new Error('jsPDF CDN failed'));
    };
    
    document.head.appendChild(script);
  });
}
